const FORBIDDEN = ["診斷","確診","病因","病症","症狀","疾病","病變",
  "治療","療效","醫治","處方","藥物","痊癒","康復","治癒",
  "風險","併發症","惡化","緊急","危險"];
const text = JSON.stringify($input.item.json, null, 0);
const violations = FORBIDDEN.filter(w => text.includes(w));
return {
  ...$input.item.json,
  violations,
  has_violations: violations.length > 0
};

